import React, { useState, useEffect, useRef } from 'react'
import { useNavigate } from 'react-router-dom'
import { supabase } from '../../lib/supabaseClient'
import { IMAGES } from '../../constants/images'

export const Profile: React.FC = () => {
  const navigate = useNavigate()
  const [loading, setLoading] = useState(true)
  const [saving, setSaving] = useState(false)
  const [user, setUser] = useState<any>(null)
  const [profile, setProfile] = useState<any>(null)
  const [editMode, setEditMode] = useState(false)
  const [message, setMessage] = useState<{ text: string; type: 'success' | 'error' | 'info' } | null>(null)

  const [formData, setFormData] = useState({
    full_name: '',
    email: '',
    sport_interests: '',
    location: '',
    role: 'Player',
    bio: '',
    skill_level: 'Beginner'
  })

  const fileInputRef = useRef<HTMLInputElement>(null)
  const [avatarUrl, setAvatarUrl] = useState<string | null>(null)
  const [uploading, setUploading] = useState(false)

  useEffect(() => {
    loadProfile()
  }, [])

  const loadProfile = async () => {
    setLoading(true)
    setMessage(null)

    const { data: { user: currentUser } } = await supabase.auth.getUser()
    if (!currentUser) {
      navigate('/login')
      return
    }
    setUser(currentUser)

    const { data: profileData, error } = await supabase
      .from('users')
      .select('*')
      .eq('id', currentUser.id)
      .single()

    if (error) {
      console.error('Profile load error:', error)
      setMessage({ text: 'Failed to load profile', type: 'error' })
    } else if (profileData) {
      setProfile(profileData)
      setFormData({
        full_name: profileData.full_name || '',
        email: profileData.email || '',
        sport_interests: profileData.sport_interests || '',
        location: profileData.location || '',
        role: profileData.role || 'Player',
        bio: profileData.bio || '',
        skill_level: profileData.skill_level || 'Beginner'
      })
      setAvatarUrl(profileData.avatar_url || null)
    }

    setLoading(false)
  }

  const handleSave = async () => {
    setSaving(true)
    setMessage(null)

    if (!formData.full_name.trim() || !formData.email.trim()) {
      setMessage({ text: 'Name and email are required', type: 'error' })
      setSaving(false)
      return
    }

    const { error } = await supabase
      .from('users')
      .update({
        full_name: formData.full_name.trim(),
        email: formData.email.trim(),
        sport_interests: formData.sport_interests || null,
        location: formData.location || null,
        role: formData.role,
        bio: formData.bio || null,
        skill_level: formData.skill_level,
        avatar_url: avatarUrl,
        updated_at: new Date().toISOString()
      })
      .eq('id', user.id)

    if (error) {
      setMessage({ text: 'Failed to save: ' + error.message, type: 'error' })
    } else {
      setMessage({ text: '✅ Profile saved successfully!', type: 'success' })
      setEditMode(false)
      await loadProfile()
    }

    setSaving(false)
  }

  const handleAvatarUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (!file) return

    // Validate file type
    if (!['image/jpeg', 'image/png', 'image/gif', 'image/webp'].includes(file.type)) {
      setMessage({ text: 'Please upload a JPEG, PNG, GIF, or WEBP image', type: 'error' })
      return
    }

    // Validate file size (max 2MB)
    if (file.size > 2 * 1024 * 1024) {
      setMessage({ text: 'Image must be less than 2MB', type: 'error' })
      return
    }

    setUploading(true)
    setMessage(null)

    try {
      const fileExt = file.name.split('.').pop()
      const fileName = `${user.id}-${Date.now()}.${fileExt}`
      const filePath = `avatars/${fileName}`

      const { error: uploadError } = await supabase.storage
        .from('avatars')
        .upload(filePath, file)

      if (uploadError) throw uploadError

      const { data: { publicUrl } } = supabase.storage
        .from('avatars')
        .getPublicUrl(filePath)

      setAvatarUrl(publicUrl)
      setMessage({ text: '✅ Avatar uploaded!', type: 'success' })

    } catch (error: any) {
      setMessage({ text: 'Upload failed: ' + error.message, type: 'error' })
    }

    setUploading(false)
  }

  const handleCancel = () => {
    setEditMode(false)
    setFormData({
      full_name: profile?.full_name || '',
      email: profile?.email || '',
      sport_interests: profile?.sport_interests || '',
      location: profile?.location || '',
      role: profile?.role || 'Player',
      bio: profile?.bio || '',
      skill_level: profile?.skill_level || 'Beginner'
    })
    setAvatarUrl(profile?.avatar_url || null)
    setMessage(null)
  }

  if (loading) {
    return (
      <div className="min-h-screen bg-[#0D0D0F] flex items-center justify-center">
        <div className="flex flex-col items-center gap-4">
          <div className="w-12 h-12 border-4 border-[#c8a200] border-t-transparent rounded-full animate-spin" />
          <p className="text-gray-500 text-sm">Loading profile...</p>
        </div>
      </div>
    )
  }

  return (
    <div className="min-h-screen bg-[#0D0D0F] relative overflow-hidden">
      {/* Background blobs */}
      <div className="ts-bg-blobs" />
      <div className="ts-bg-spotlight" />

      <div className="relative z-10 max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Header */}
        <div className="mb-8">
          <div className="flex items-center gap-3 mb-2">
            <div className="p-2 bg-[#c8a200]/10 rounded-xl border border-[#c8a200]/20">
              <span className="text-lg">👤</span>
            </div>
            <span className="text-[#c8a200] text-sm font-medium tracking-wider uppercase">Profile</span>
          </div>
          <h1 className="text-3xl md:text-4xl font-bold text-white">
            Your Profile
          </h1>
          <p className="text-gray-400 text-sm mt-1">Manage your personal information</p>
        </div>

        {/* Message */}
        {message && (
          <div className={`p-4 rounded-xl mb-6 border ${
            message.type === 'success' 
              ? 'bg-green-500/10 border-green-500/30 text-green-400'
              : message.type === 'error'
              ? 'bg-red-500/10 border-red-500/30 text-red-400'
              : 'bg-blue-500/10 border-blue-500/30 text-blue-400'
          }`}>
            {message.text}
          </div>
        )}

        {/* Profile Card */}
        <div className="ts-card p-6 md:p-8">
          {/* Avatar Section */}
          <div className="flex flex-col sm:flex-row items-center gap-6 mb-8 pb-8 border-b border-white/5">
            <div className="relative group">
              <div className="w-28 h-28 rounded-2xl overflow-hidden bg-gradient-to-br from-[#c8a200]/20 to-[#FFD700]/10 border-2 border-[#c8a200]/30 flex items-center justify-center">
                {avatarUrl ? (
                  <img src={avatarUrl} alt="Avatar" className="w-full h-full object-cover" />
                ) : (
                  <span className="text-4xl font-bold text-[#c8a200]">
                    {formData.full_name?.charAt(0)?.toUpperCase() || '?'}
                  </span>
                )}
              </div>
              {editMode && (
                <button
                  onClick={() => fileInputRef.current?.click()}
                  disabled={uploading}
                  className="absolute bottom-0 right-0 p-2 bg-[#c8a200] rounded-full hover:bg-[#FFD700] transition-colors shadow-lg shadow-[#c8a200]/30"
                >
                  {uploading ? (
                    <div className="w-4 h-4 border-2 border-black border-t-transparent rounded-full animate-spin" />
                  ) : (
                    <svg className="w-4 h-4 text-black" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" />
                    </svg>
                  )}
                </button>
              )}
              <input
                ref={fileInputRef}
                type="file"
                accept="image/*"
                onChange={handleAvatarUpload}
                className="hidden"
              />
            </div>

            <div className="flex-1 text-center sm:text-left">
              <h2 className="text-2xl font-bold text-white">
                {formData.full_name || 'Your Name'}
              </h2>
              <p className="text-gray-400 text-sm">{formData.email}</p>
              <div className="flex flex-wrap gap-2 mt-3 justify-center sm:justify-start">
                <span className="ts-badge-gold">{formData.role}</span>
                <span className="ts-badge-gold ts-badge-success">{formData.skill_level}</span>
              </div>
            </div>

            {!editMode && (
              <button
                onClick={() => setEditMode(true)}
                className="ts-btn-gold"
              >
                ✏️ Edit Profile
              </button>
            )}
          </div>

          {/* Form */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <label className="block text-gray-400 text-sm font-medium mb-2">Full Name *</label>
              <input
                type="text"
                value={formData.full_name}
                onChange={(e) => setFormData({ ...formData, full_name: e.target.value })}
                disabled={!editMode}
                className={`ts-input ${!editMode ? 'opacity-60 cursor-not-allowed' : ''}`}
                placeholder="Your full name"
              />
            </div>

            <div>
              <label className="block text-gray-400 text-sm font-medium mb-2">Email *</label>
              <input
                type="email"
                value={formData.email}
                onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                disabled={!editMode}
                className={`ts-input ${!editMode ? 'opacity-60 cursor-not-allowed' : ''}`}
                placeholder="your@email.com"
              />
            </div>

            <div>
              <label className="block text-gray-400 text-sm font-medium mb-2">Sport Interest</label>
              <select
                value={formData.sport_interests}
                onChange={(e) => setFormData({ ...formData, sport_interests: e.target.value })}
                disabled={!editMode}
                className={`ts-input ts-select ${!editMode ? 'opacity-60 cursor-not-allowed' : ''}`}
              >
                <option value="">Select a sport</option>
                {['Football', 'Basketball', 'Cricket', 'Tennis', 'Badminton', 'Volleyball', 'Swimming', 'Running', 'Cycling', 'Hockey', 'Other'].map(sport => (
                  <option key={sport} value={sport}>{sport}</option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-gray-400 text-sm font-medium mb-2">Location</label>
              <input
                type="text"
                value={formData.location}
                onChange={(e) => setFormData({ ...formData, location: e.target.value })}
                disabled={!editMode}
                className={`ts-input ${!editMode ? 'opacity-60 cursor-not-allowed' : ''}`}
                placeholder="City, Country"
              />
            </div>

            <div>
              <label className="block text-gray-400 text-sm font-medium mb-2">Role</label>
              <select
                value={formData.role}
                onChange={(e) => setFormData({ ...formData, role: e.target.value })}
                disabled={!editMode}
                className={`ts-input ts-select ${!editMode ? 'opacity-60 cursor-not-allowed' : ''}`}
              >
                <option value="Player">Player</option>
                <option value="Coach">Coach</option>
                <option value="Organizer">Organizer</option>
              </select>
            </div>

            <div>
              <label className="block text-gray-400 text-sm font-medium mb-2">Skill Level</label>
              <select
                value={formData.skill_level}
                onChange={(e) => setFormData({ ...formData, skill_level: e.target.value })}
                disabled={!editMode}
                className={`ts-input ts-select ${!editMode ? 'opacity-60 cursor-not-allowed' : ''}`}
              >
                <option value="Beginner">Beginner</option>
                <option value="Intermediate">Intermediate</option>
                <option value="Advanced">Advanced</option>
                <option value="Professional">Professional</option>
              </select>
            </div>

            <div className="md:col-span-2">
              <label className="block text-gray-400 text-sm font-medium mb-2">Bio</label>
              <textarea
                value={formData.bio}
                onChange={(e) => setFormData({ ...formData, bio: e.target.value })}
                disabled={!editMode}
                rows={4}
                className={`ts-input ${!editMode ? 'opacity-60 cursor-not-allowed' : ''}`}
                placeholder="Tell others about yourself and your sports experience..."
                style={{ resize: 'vertical', fontFamily: 'inherit' }}
              />
            </div>
          </div>

          {/* Action Buttons */}
          {editMode && (
            <div className="flex flex-wrap gap-3 mt-8 pt-6 border-t border-white/5">
              <button
                onClick={handleSave}
                disabled={saving}
                className="ts-btn-gold flex-1 sm:flex-none"
              >
                {saving ? 'Saving...' : '💾 Save Changes'}
              </button>
              <button
                onClick={handleCancel}
                disabled={saving}
                className="ts-btn-ghost flex-1 sm:flex-none"
              >
                Cancel
              </button>
            </div>
          )}
        </div>

        {/* Stats Section */}
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 mt-6">
          {[
            { label: 'Sessions Joined', value: '12', emoji: '📅' },
            { label: 'Sessions Created', value: '5', emoji: '🏃' },
            { label: 'Listings', value: '3', emoji: '🛒' },
            { label: 'Posts', value: '8', emoji: '📝' },
          ].map((stat, i) => (
            <div key={i} className="ts-card p-4 text-center">
              <div className="text-2xl mb-1">{stat.emoji}</div>
              <div className="text-2xl font-bold text-white">{stat.value}</div>
              <div className="text-gray-400 text-xs mt-1">{stat.label}</div>
            </div>
          ))}
        </div>
      </div>
    </div>
  )
}
